'use client';

import { useEffect, useState } from 'react';
import { VocabularyWordDto } from '@soenglish/shared-types';
import { Badge, Button, Field, PageHeader, StatTile } from '../../components/ui';
import styles from './page.module.scss';

export default function VocabularyPage() {
  const [words, setWords] = useState<VocabularyWordDto[]>([]);
  const [filter, setFilter] = useState('All');
  const [statusFilter, setStatusFilter] = useState('all');
  const [mode, setMode] = useState<'list' | 'flashcard'>('list');
  const [cardIndex, setCardIndex] = useState(0);
  const [flipped, setFlipped] = useState(false);
  const [search, setSearch] = useState('');
  const categories = ['All', 'communication', 'business', 'finance', 'general'];

  useEffect(() => {
    const baseUrl = process.env.NEXT_PUBLIC_API_URL ?? 'http://localhost:3000/api';
    fetch(`${baseUrl}/vocabulary/words`)
      .then((r) => r.json())
      .then(setWords);
  }, []);

  const filtered = words.filter((word) => {
    const catOk = filter === 'All' || word.category === filter;
    const statusOk = statusFilter === 'all' || word.status === statusFilter;
    const searchOk =
      !search ||
      word.word.toLowerCase().includes(search.toLowerCase()) ||
      word.definition.toLowerCase().includes(search.toLowerCase());
    return catOk && statusOk && searchOk;
  });

  const currentCard = filtered[cardIndex];
  const markStatus = (status: VocabularyWordDto['status']) => {
    setWords((prev) => prev.map((word) => (word.id === currentCard.id ? { ...word, status } : word)));
    setFlipped(false);
    setTimeout(() => setCardIndex((i) => Math.min(i + 1, filtered.length - 1)), 300);
  };

  const stats = {
    new: words.filter((word) => word.status === 'new').length,
    learning: words.filter((word) => word.status === 'learning').length,
    known: words.filter((word) => word.status === 'known').length,
  };

  return (
    <div className={`${styles.page} container container--page`}>
      <PageHeader
        className={styles.pageHeader}
        textClassName={styles.pageHeaderText}
        titleClassName={styles.pageTitle}
        subtitleClassName={styles.pageSub}
        title="Vocabulary"
        subtitle={`${words.length} words in your library`}
        actions={
          <div className={styles.modeToggle}>
          <Button
            type="button"
            className={`${styles.modeBtn} ${mode === 'list' ? styles.modeActive : ''}`}
            onClick={() => setMode('list')}
          >
            <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
              <path d="M2 4h12M2 8h12M2 12h8" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
            </svg>
            List
          </Button>
          <Button
            type="button"
            className={`${styles.modeBtn} ${mode === 'flashcard' ? styles.modeActive : ''}`}
            onClick={() => {
              setMode('flashcard');
              setCardIndex(0);
              setFlipped(false);
            }}
          >
            <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
              <rect x="2" y="4" width="12" height="9" rx="1.5" stroke="currentColor" strokeWidth="1.5" />
              <path d="M5 4V3a1 1 0 0 1 1-1h4a1 1 0 0 1 1 1v1" stroke="currentColor" strokeWidth="1.5" />
            </svg>
            Flashcards
          </Button>
          </div>
        }
      />

      <div className={styles.statsRow}>
        <StatTile
          className={styles.statChip}
          interactive
          onClick={() => setStatusFilter('all')}
          label="Total"
          labelClassName={styles.statLbl}
          value={words.length}
          valueClassName={styles.statNum}
        />
        <StatTile
          className={`${styles.statChip} ${styles.statBlue}`}
          interactive
          onClick={() => setStatusFilter('new')}
          label="New"
          labelClassName={styles.statLbl}
          value={stats.new}
          valueClassName={styles.statNum}
        />
        <StatTile
          className={`${styles.statChip} ${styles.statAmber}`}
          interactive
          onClick={() => setStatusFilter('learning')}
          label="Learning"
          labelClassName={styles.statLbl}
          value={stats.learning}
          valueClassName={styles.statNum}
        />
        <StatTile
          className={`${styles.statChip} ${styles.statGreen}`}
          interactive
          onClick={() => setStatusFilter('known')}
          label="Known"
          labelClassName={styles.statLbl}
          value={stats.known}
          valueClassName={styles.statNum}
        />
      </div>

      {mode === 'list' && (
        <>
          <div className={styles.filters}>
            <Field
              className={styles.searchInput}
              placeholder="Search words..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
            <div className={styles.catFilters}>
              {categories.map((category) => (
                <Button
                  type="button"
                  key={category}
                  className={`${styles.catBtn} ${filter === category ? styles.catActive : ''}`}
                  onClick={() => setFilter(category)}
                >
                  {category.charAt(0).toUpperCase() + category.slice(1)}
                </Button>
              ))}
            </div>
          </div>

          <div className={styles.wordGrid}>
            {filtered.map((word, i) => (
              <div key={word.id} className={styles.wordCard} style={{ animationDelay: `${i * 0.03}s` }}>
                <div className={styles.wcTop}>
                  <div>
                    <div className={styles.wcWord}>{word.word}</div>
                    <div className={styles.wcPhonetic}>{word.phonetic}</div>
                  </div>
                  <Badge
                    className={`${styles.wcStatus} ${styles[word.status === 'new' ? 'blue' : word.status === 'learning' ? 'amber' : 'green']}`}
                    variant={word.status === 'new' ? 'blue' : word.status === 'learning' ? 'amber' : 'green'}
                  >
                    {word.status}
                  </Badge>
                </div>
                <div className={styles.wcPos}>{word.pos}</div>
                <div className={styles.wcDef}>{word.definition}</div>
                <div className={styles.wcExample}>&quot;{word.example}&quot;</div>
                <div className={styles.wcActions}>
                  {(['new', 'learning', 'known'] as const).map((status) => (
                    <Button
                      type="button"
                      key={status}
                      className={`${styles.wcBtn} ${word.status === status ? styles.wcBtnActive : ''}`}
                      onClick={() =>
                        setWords((prev) => prev.map((item) => (item.id === word.id ? { ...item, status } : item)))
                      }
                    >
                      {status}
                    </Button>
                  ))}
                </div>
              </div>
            ))}
          </div>
          {filtered.length === 0 && <div className={styles.empty}>No words found. Try a different filter.</div>}
        </>
      )}

      {mode === 'flashcard' && (
        <div className={`container container--form ${styles.flashcardMode}`}>
          <div className={styles.fcProgress}>
            <span>
              {cardIndex + 1} / {filtered.length}
            </span>
            <div className={styles.fcBar}>
              <div className={styles.fcBarFill} style={{ width: `${((cardIndex + 1) / filtered.length) * 100}%` }} />
            </div>
          </div>

          {currentCard ? (
            <>
              <div className={`${styles.flashcard} ${flipped ? styles.flipped : ''}`} onClick={() => setFlipped((f) => !f)}>
                <div className={styles.fcFront}>
                  <div className={styles.fcHint}>Click to reveal definition</div>
                  <div className={styles.fcWord}>{currentCard.word}</div>
                  <div className={styles.fcPhonetic}>{currentCard.phonetic}</div>
                  <div className={styles.fcCategory}>
                    {currentCard.category} · {currentCard.pos}
                  </div>
                </div>
                <div className={styles.fcBack}>
                  <div className={styles.fcDef}>{currentCard.definition}</div>
                  <div className={styles.fcExample}>&quot;{currentCard.example}&quot;</div>
                </div>
              </div>

              {flipped && (
                <div className={styles.fcButtons}>
                  <Button type="button" className={`${styles.fcBtn} ${styles.fcBtnRed}`} onClick={() => markStatus('new')}>
                    Still learning
                  </Button>
                  <Button type="button" className={`${styles.fcBtn} ${styles.fcBtnAmber}`} onClick={() => markStatus('learning')}>
                    Almost got it
                  </Button>
                  <Button type="button" className={`${styles.fcBtn} ${styles.fcBtnGreen}`} onClick={() => markStatus('known')}>
                    Know it! ✓
                  </Button>
                </div>
              )}

              <div className={styles.fcNav}>
                <Button
                  type="button"
                  className={styles.fcNavBtn}
                  onClick={() => {
                    setCardIndex((i) => Math.max(0, i - 1));
                    setFlipped(false);
                  }}
                  disabled={cardIndex === 0}
                >
                  ← Prev
                </Button>
                <Button
                  type="button"
                  className={styles.fcNavBtn}
                  onClick={() => {
                    setCardIndex((i) => Math.min(filtered.length - 1, i + 1));
                    setFlipped(false);
                  }}
                  disabled={cardIndex === filtered.length - 1}
                >
                  Next →
                </Button>
              </div>
            </>
          ) : (
            <div className={styles.fcComplete}>
              <div className={styles.fcCompleteIcon}>🎉</div>
              <div className={styles.fcCompleteTitle}>All done!</div>
              <div className={styles.fcCompleteSub}>You reviewed all {words.length} words. Great work!</div>
              <Button
                type="button"
                className={styles.fcRestartBtn}
                onClick={() => {
                  setCardIndex(0);
                  setFlipped(false);
                }}
              >
                Review again
              </Button>
            </div>
          )}
        </div>
      )}
    </div>
  );
}
